--
-- Create model NYCoADocketEntry
--
-- PERF: CREATE TABLE on empty table — safe and instantaneous.
CREATE TABLE "search_nycoadocketentry" ("id" integer NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "date_created" timestamp with time zone NOT NULL, "date_modified" timestamp with time zone NOT NULL, "sequence_number" varchar(32) NOT NULL, "date_filed" date NULL, "description" text NOT NULL, "filing_type" text NOT NULL, "party_side" text NOT NULL, "docket_id" integer NOT NULL);
-- PERF: COMMENT ON COLUMN is metadata-only — instantaneous.
COMMENT ON COLUMN "search_nycoadocketentry"."sequence_number" IS 'Stable ordering key. For FILINGS-derived entries it is the ISO date plus a zero-padded index; for file-only entries it is the literal "file." prefix plus a zero-padded file index. Disjoint by prefix so the natural key (docket, sequence_number) never collides across origins.';
COMMENT ON COLUMN "search_nycoadocketentry"."date_filed" IS 'Date the entry was received by the court.';
COMMENT ON COLUMN "search_nycoadocketentry"."description" IS 'Free-text description. For FILINGS entries the FILINGS row''s filing_type concatenated with party; for file-only entries the file''s display name.';
COMMENT ON COLUMN "search_nycoadocketentry"."filing_type" IS 'Court-PASS filing-type string when known (Appellant Brief, Respondent Brief, etc.). Empty for file-only entries.';
COMMENT ON COLUMN "search_nycoadocketentry"."party_side" IS 'Party-side label when known (Appellant, Respondent, Amicus Curiae, etc.). Empty for file-only entries.';
COMMENT ON COLUMN "search_nycoadocketentry"."docket_id" IS 'The Docket this entry belongs to.';
--
-- Create model NYCoADocument
--
-- PERF: CREATE TABLE on empty table — safe.
CREATE TABLE "search_nycoadocument" ("id" integer NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "date_created" timestamp with time zone NOT NULL, "date_modified" timestamp with time zone NOT NULL, "sha1" varchar(40) NOT NULL, "page_count" integer NULL, "file_size" integer NULL, "filepath_local" varchar(1000) NOT NULL, "filepath_ia" varchar(1000) NOT NULL, "ia_upload_failure_count" smallint NULL, "thumbnail" varchar(100) NULL, "thumbnail_status" smallint NOT NULL, "plain_text" text NOT NULL, "ocr_status" smallint NULL, "file_name" text NOT NULL, "file_index" integer NULL, "docket_entry_id" integer NOT NULL UNIQUE);
COMMENT ON COLUMN "search_nycoadocument"."file_name" IS 'Raw filename from Court-PASS''s gvFiles row.';
COMMENT ON COLUMN "search_nycoadocument"."file_index" IS '0-based position in the files table on the filing-detail page.';
COMMENT ON COLUMN "search_nycoadocument"."docket_entry_id" IS 'The entry this file is attached to.';
